// Verify HMAC signature
const crypto = require('crypto');

const webhookBody = $('Webhook Trigger').first().json.body;
const headers = $('Webhook Trigger').first().json.headers;
const secret = $('Workflow Constants').first().json.N8N_SHARED_SECRET;

const signature = headers['x-profunda-signature'];
if (!signature) {
  throw new Error('Missing x-profunda-signature header');
}

if (!webhookBody || typeof webhookBody !== 'object') {
  throw new Error('Missing or invalid webhook body');
}

if (webhookBody.workflow_key !== 'event_attendee_enrich') {
  throw new Error('workflow_key must be event_attendee_enrich, got: ' + webhookBody.workflow_key);
}

if (!webhookBody.run_id || typeof webhookBody.run_id !== 'string') {
  throw new Error('Missing run_id');
}

// Compute HMAC over the raw body JSON
const bodyStr = JSON.stringify(webhookBody);
const hmac = crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');

if (hmac !== signature) {
  throw new Error('Invalid HMAC signature');
}

return [{ json: webhookBody }];

const input = $('Verify Signature').first().json;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!input.event_id || typeof input.event_id !== 'string' || !UUID_RE.test(input.event_id)) {
  throw new Error('event_id must be a valid UUID');
}

const result = {
  run_id: input.run_id,
  workflow_key: 'event_attendee_enrich',
  event_id: input.event_id,
  triggered_by: input.triggered_by || null
};

// Optional attendee_ids
if (input.attendee_ids !== undefined && input.attendee_ids !== null) {
  if (!Array.isArray(input.attendee_ids)) {
    throw new Error('attendee_ids must be an array of UUIDs');
  }
  for (const id of input.attendee_ids) {
    if (typeof id !== 'string' || !UUID_RE.test(id)) {
      throw new Error('Each attendee_id must be a valid UUID');
    }
  }
  const capped = input.attendee_ids.slice(0, 50);
  if (capped.length > 0) {
    result.attendee_ids = capped;
  }
}

return [{ json: result }];

// Deterministic enrichment: normalize attendee data, compute completeness scores
const input = $('Validate Input').first().json;
const fetchResult = $('Fetch Attendees').first().json;

// Check if fetch failed
const fetchError = $('Fetch Attendees').first().json?.error || null;
const fetchStatusCode = $('Fetch Attendees').first().json?.statusCode;

let attendees = [];
if (Array.isArray(fetchResult)) {
  attendees = fetchResult;
} else if (fetchResult && Array.isArray(fetchResult.data)) {
  attendees = fetchResult.data;
} else if (fetchResult && !fetchError) {
  // Single object or unexpected shape
  attendees = [fetchResult];
}

const enriched_attendees = attendees.map(a => {
  const fields = ['name', 'email', 'title', 'organization', 'phone'];
  const filled = fields.filter(f => a[f] && String(a[f]).trim().length > 0).length;
  const completeness = Math.round((filled / fields.length) * 100);

  return {
    id: a.id || a.attendee_id || null,
    contact_id: a.contact_id || null,
    name: a.name || null,
    email: a.email || null,
    title: a.title || null,
    organization: a.organization || null,
    phone: a.phone || null,
    completeness_score: completeness,
    needs_enrichment: completeness < 60,
    enrichment_source: 'deterministic_v1'
  };
});

return [{
  json: {
    run_id: input.run_id,
    event_id: input.event_id,
    enriched_attendees,
    attendee_count: enriched_attendees.length,
    fetch_error: fetchError
  }
}];

const input = $('Validate Input').first().json;

// Check each upstream node for errors
let error = null;
let failed_node = null;

try {
  const fetchNode = $('Fetch Attendees').first();
  if (fetchNode.json?.error) {
    error = 'Fetch attendees failed: ' + String(fetchNode.json.error).slice(0, 500);
    failed_node = 'Fetch Attendees';
  }
} catch (e) {
  error = 'Fetch Attendees node did not execute: ' + String(e.message).slice(0, 200);
  failed_node = 'Fetch Attendees';
}

if (!error) {
  try {
    const enrichNode = $('Enrich Attendees').first();
    if (enrichNode.json?.error) {
      error = 'Enrich failed: ' + String(enrichNode.json.error).slice(0, 500);
      failed_node = 'Enrich Attendees';
    }
  } catch (e) {
    error = 'Enrich Attendees node did not execute: ' + String(e.message).slice(0, 200);
    failed_node = 'Enrich Attendees';
  }
}

let result = null;
if (!error) {
  try {
    const enrichData = $('Enrich Attendees').first().json;
    result = {
      enriched_attendees: enrichData.enriched_attendees || [],
      attendee_count: enrichData.attendee_count || 0,
      event_id: enrichData.event_id
    };
    if (enrichData.fetch_error) {
      error = 'Fetch returned error: ' + String(enrichData.fetch_error).slice(0, 500);
      failed_node = 'Fetch Attendees';
    }
  } catch (e) {
    error = 'Failed to build result envelope: ' + String(e.message).slice(0, 200);
    failed_node = 'Result Envelope';
  }
}

return [{
  json: {
    run_id: input.run_id,
    workflow_key: 'event_attendee_enrich',
    payload: {
      result: result,
      error: error,
      failed_node: failed_node
    }
  }
}];
